#!/usr/bin/env python3
"""Generate real educational content for all 10 placeholder course JSON files."""
import json, os

BASE = os.path.dirname(os.path.abspath(__file__))
OUT = os.path.join(BASE, "content_data")

def build_lesson(unit, idx, title, course_name, summary_html, flashcards, quiz):
    key = f"u{unit}_l{unit}.{idx}"
    fc_list = [{"question": t, "answer": d, "data_i18n_q": None, "data_i18n_a": None} for t, d in flashcards]
    q_list = []
    for qi, (qt, opts, exp) in enumerate(quiz, 1):
        options = []
        for o in opts:
            correct = o.startswith("*")
            options.append({"text": o.lstrip("*"), "is_correct": correct, "data_i18n": None})
        q_list.append({"question_number": qi, "question_text": qt, "attempted": 2, "data_i18n": None, "options": options, "explanation": exp})
    return key, {
        "unit": unit, "lesson_number": f"{unit}.{idx}", "title": title, "course": course_name,
        "summary_sections": [{"title": f"Key Concepts: {title}", "content_html": summary_html, "data_i18n": None}],
        "flashcards": fc_list, "quiz_questions": q_list
    }

def write_course(slug, course_name, units_data):
    data = {}
    for unit_num, lessons in sorted(units_data.items()):
        for idx, (title, html, cards, quiz) in enumerate(lessons, 1):
            key, lesson = build_lesson(unit_num, idx, title, course_name, html, cards, quiz)
            data[key] = lesson
    path = os.path.join(OUT, f"{slug}_lessons.json")
    with open(path, 'w', encoding='utf-8') as f:
        json.dump(data, f, indent=2, ensure_ascii=False)
    print(f"  ✓ {slug}_lessons.json — {len(data)} lessons")

